#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
int main(){
    ll n;
    cin>>n;
    for(ll i=1;i<=n;i++){
        for(ll j=1;j<=i;j++){
            ll ans=pow(i,j);
            printf("%lld ^ %lld = %lld ",i,j,ans);
        }
        cout<<endl;
    }
    return 0;
}
